parameters.jsCode:
const rpcResult = $input.first().json;
const rawText = rpcResult.result.content[0].text;
const toolResult = JSON.parse(rawText);

return [{
  json: {
    baseUrl: $('Set Workflow Variables').first().json.baseUrl,
    authToken: $('Set Workflow Variables').first().json.authToken,
    pipelineId: $('Set Workflow Variables').first().json.pipelineId,
    agentId: $('Set Workflow Variables').first().json.agentId,
    task: $('Set Workflow Variables').first().json.task,
    context: toolResult.context,
    session_id: toolResult.session_id,
    pending_whisper_ids: toolResult.pending_whisper_ids || [],
    telemetry: toolResult.telemetry || {}
  }
}];

