parameters.jsCode:
const prev = $('Extract Context').first().json;
const llmResponse = $input.first().json;

const resultText = llmResponse.choices && llmResponse.choices[0]
  ? llmResponse.choices[0].message.content
  : "REPLACE_WITH_LLM_OUTPUT";

return [{
  json: {
    baseUrl: prev.baseUrl,
    authToken: prev.authToken,
    pipelineId: prev.pipelineId,
    agentId: prev.agentId,
    task: prev.task,
    pending_whisper_ids: prev.pending_whisper_ids,
    result_summary: resultText.slice(0, 120),
    result_full: resultText
  }
}];

